package model

import (
	"os"
	"path/filepath"
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"

	"github.com/black-atom-industries/helm/internal/config"
	"github.com/black-atom-industries/helm/internal/git"
	"github.com/black-atom-industries/helm/internal/tmux"
	"github.com/black-atom-industries/helm/internal/ui"
)

func (m *Model) handleBookmarksMode(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	keys := ui.DefaultKeyMap

	switch {
	case key.Matches(msg, keys.Cancel):
		// If filter is active, clear it first
		if m.bookmarkList.Filter() != "" {
			m.bookmarkList.SetFilter("")
			return m, nil
		}
		// Otherwise return to normal mode
		m.mode = ModeNormal
		return m, nil

	case key.Matches(msg, keys.Up):
		m.bookmarkList.MoveCursor(-1)

	case key.Matches(msg, keys.Down):
		m.bookmarkList.MoveCursor(1)

	case key.Matches(msg, keys.Expand):
		// Expand bookmark if it has a session
		if selected, ok := m.bookmarkList.SelectedItem(); ok {
			sessionName := m.extractSessionName(selected.Path)
			if session := m.findSessionByName(sessionName); session != nil {
				m.bookmarkExpanded[selected.Path] = true
			}
		}

	case key.Matches(msg, keys.Collapse):
		// Collapse bookmark
		if selected, ok := m.bookmarkList.SelectedItem(); ok {
			m.bookmarkExpanded[selected.Path] = false
		}

	case key.Matches(msg, keys.Select):
		if selected, ok := m.bookmarkList.SelectedItem(); ok {
			return m.openBookmark(selected)
		}

	case key.Matches(msg, keys.PickDirectory):
		// C-p moves bookmark up in bookmarks mode
		return m.moveBookmark(-1)

	case key.Matches(msg, keys.Create):
		// C-n moves bookmark down in bookmarks mode
		return m.moveBookmark(1)

	case key.Matches(msg, keys.Kill):
		return m.removeBookmark()

	case key.Matches(msg, keys.AddBookmark):
		// Open project picker to add a new bookmark
		m.mode = ModePickDirectory
		m.returnToBookmarks = true
		m.projectList.Reset()
		m.projectList.SetItems(m.scanProjectDirectories())
		return m, tea.WindowSize()

	case key.Matches(msg, keys.Quit):
		return m, tea.Quit

	case msg.Type == tea.KeyBackspace:
		filter := m.bookmarkList.Filter()
		if len(filter) > 0 {
			m.bookmarkList.SetFilter(filter[:len(filter)-1])
		}

	case msg.Type == tea.KeyRunes:
		m.bookmarkList.SetFilter(m.bookmarkList.Filter() + string(msg.Runes))
	}

	return m, nil
}

// addPathToBookmarks adds a path to bookmarks
func (m *Model) addPathToBookmarks(path string) (tea.Model, tea.Cmd) {
	// Check if already bookmarked
	for _, b := range m.config.Bookmarks {
		if b.Path == path {
			m.setError("Already bookmarked")
			return m, nil
		}
	}

	// Add bookmark
	m.config.Bookmarks = append(m.config.Bookmarks, config.Bookmark{
		Path: path,
	})

	// Save config
	if err := m.config.SaveBookmarks(); err != nil {
		m.setError("Failed to save config: %v", err)
		return m, nil
	}

	m.setMessage("Added bookmark: %s", filepath.Base(path))
	return m, nil
}

// addSelectedToBookmarks adds the currently selected session to bookmarks
func (m *Model) addSelectedToBookmarks() (tea.Model, tea.Cmd) {
	if len(m.items) == 0 || m.cursor >= len(m.items) {
		return m, nil
	}

	item := m.items[m.cursor]
	if item.Type != ItemTypeSession {
		m.setError("Select a session to bookmark")
		return m, nil
	}

	session := m.getSession(item)
	// Get session path from tmux
	path, err := git.GetSessionPath(session.Name)
	if err != nil || path == "" {
		// Fallback: assume it's in one of the project dirs
		for _, dir := range m.config.ProjectDirs {
			possiblePath := filepath.Join(dir, session.Name)
			if _, err := os.Stat(possiblePath); err == nil {
				path = possiblePath
				break
			}
		}
	}

	if path == "" {
		m.setError("Could not determine path for session")
		return m, nil
	}

	// Check if already bookmarked
	for _, b := range m.config.Bookmarks {
		if b.Path == path || filepath.Base(b.Path) == session.Name {
			m.setError("Session already bookmarked")
			return m, nil
		}
	}

	// Add bookmark
	m.config.Bookmarks = append(m.config.Bookmarks, config.Bookmark{
		Path: path,
	})

	// Save config
	if err := m.config.SaveBookmarks(); err != nil {
		m.setError("Failed to save config: %v", err)
		return m, nil
	}

	m.setMessage("Added bookmark: %s", session.Name)
	return m, nil
}

// openBookmark opens or switches to a bookmarked session
func (m *Model) openBookmark(bookmark config.Bookmark) (tea.Model, tea.Cmd) {
	sessionName := m.extractSessionName(bookmark.Path)

	// Create session if it doesn't exist
	if !tmux.SessionExists(sessionName) {
		if err := tmux.CreateSession(sessionName, bookmark.Path); err != nil {
			m.setError("Failed to create session: %v", err)
			return m, nil
		}

		// Apply layout if configured
		m.applyLayout(sessionName, bookmark.Path)
	}

	// Switch to the session
	if err := tmux.SwitchClient(sessionName); err != nil {
		m.setError("Failed to switch to session: %v", err)
		return m, nil
	}

	return m, tea.Quit
}

// moveBookmark moves the selected bookmark up or down
func (m *Model) moveBookmark(delta int) (tea.Model, tea.Cmd) {
	cursor := m.bookmarkList.Cursor()
	newPos := cursor + delta

	if newPos < 0 || newPos >= len(m.config.Bookmarks) {
		return m, nil
	}

	// Swap bookmarks
	m.config.Bookmarks[cursor], m.config.Bookmarks[newPos] = m.config.Bookmarks[newPos], m.config.Bookmarks[cursor]

	// Save config
	if err := m.config.SaveBookmarks(); err != nil {
		m.setError("Failed to save config: %v", err)
		return m, nil
	}

	// Update list and cursor
	m.bookmarkList.SetItems(m.config.Bookmarks)
	m.bookmarkList.SetCursor(newPos)

	return m, nil
}

// removeBookmark removes the selected bookmark
func (m *Model) removeBookmark() (tea.Model, tea.Cmd) {
	cursor := m.bookmarkList.Cursor()
	if cursor < 0 || cursor >= len(m.config.Bookmarks) {
		return m, nil
	}

	// Remove bookmark
	m.config.Bookmarks = append(m.config.Bookmarks[:cursor], m.config.Bookmarks[cursor+1:]...)

	// Save config
	if err := m.config.SaveBookmarks(); err != nil {
		m.setError("Failed to save config: %v", err)
		return m, nil
	}

	// Update list
	m.bookmarkList.SetItems(m.config.Bookmarks)

	m.setMessage("Bookmark removed")
	return m, nil
}

func (m Model) viewBookmarks() string {
	var header strings.Builder
	var b strings.Builder
	filter := m.bookmarkList.Filter()

	// Fixed header: title bar + prompt + border
	header.WriteString(ui.RenderTitleBar(config.AppName, m.mode.String(), m.width))
	header.WriteString("\n")
	header.WriteString(ui.RenderPrompt(filter, m.width))
	header.WriteString("\n")
	header.WriteString(ui.RenderBorder(m.borderWidth()))
	header.WriteString("\n")

	// Content area

	if m.bookmarkList.Len() == 0 {
		if filter != "" {
			b.WriteString("  No bookmarks matching filter\n")
		} else {
			b.WriteString("  No bookmarks configured\n")
			b.WriteString("  Press C-a to add a bookmark\n")
			// line count tracked by renderWithSidebar
		}
		// line count tracked by renderWithSidebar
	} else {
		// Calculate max visible items (includes table header)
		contentH := m.contentHeight()
		maxItems := ui.DefaultVisibleItems
		if contentH > 0 {
			if available := contentH - 8 - ui.ActionBarHeight; available > 0 { // header(3) + footer(3) + actionBar(3) + tableHeader(1) + dottedLine(1)
				maxItems = available
			}
		}
		m.bookmarkList.SetHeight(maxItems)

		visibleBookmarks := m.bookmarkList.VisibleItems()
		scrollOffset := m.bookmarkList.ScrollOffset()

		// Calculate layout for bookmarks - use shared maxNameWidth for consistency
		maxGitWidth := 0
		for _, bookmark := range visibleBookmarks {
			// Check if session has git status
			sessionName := m.extractSessionName(bookmark.Path)
			if _, ok := m.gitStatuses[sessionName]; ok && m.config.GitStatusEnabled {
				if ui.GitStatusColumnWidth > maxGitWidth {
					maxGitWidth = ui.GitStatusColumnWidth
				}
			}
		}

		layout := ui.RowLayout{
			NameWidth:      m.maxNameWidth, // Use shared width for stable layout
			GitStatusWidth: maxGitWidth,
		}

		// Table header row
		header := ui.RenderTableHeader(layout, ui.TableHeaderOpts{
			ShowExpandIcon: false,
			ShowTime:       false,
			ShowGit:        maxGitWidth > 0,
			ShowCC:         true, // Always show CC in header when data rows have it reserved
			ShowPi:         true, // Always show Pi in header when data rows have it reserved
			NameLabel:      "BKMK",
		})
		b.WriteString(header)
		b.WriteString("\n")
		b.WriteString(ui.RenderDottedBorder(m.sessionListWidth()))
		b.WriteString("\n")
		// line count tracked by renderWithSidebar

		scrollbar := ui.ScrollbarChars(m.bookmarkList.Len(), m.bookmarkList.Height(), scrollOffset, len(visibleBookmarks))

		for i, bookmark := range visibleBookmarks {
			absoluteIdx := scrollOffset + i
			selected := m.bookmarkList.IsSelected(absoluteIdx)
			slot := absoluteIdx

			if i < len(scrollbar) {
				if selected {
					b.WriteString(ui.SpacerStyle(scrollbar[i]+" ", true))
				} else {
					b.WriteString(scrollbar[i])
					b.WriteString(" ")
				}
			}

			sessionName := m.extractSessionName(bookmark.Path)
			session := m.findSessionByName(sessionName)
			expanded := m.bookmarkExpanded[bookmark.Path]

			if session != nil {
				// Session exists - show full session data with expand icon
				lastActivity := session.LastActivity
				opts := ui.SessionRowOpts{
					RowOpts: ui.RowOpts{
						Num:            slot,
						Name:           sessionName,
						Selected:       selected,
						ShowExpandIcon: true,
						Expanded:       expanded,
						LastActivity:   &lastActivity,
						AnimFrame:      m.animationFrame,
					},
				}
				if status, ok := m.gitStatuses[sessionName]; ok {
					opts.GitStatus = &status
				}
				if m.gitStatusShowLoading && m.gitStatusPending[sessionName] {
					opts.GitStatusLoading = true
				}
				if status, ok := m.claudeStatuses[sessionName]; ok {
					opts.ClaudeStatus = &status
				}
				if status, ok := m.piStatuses[sessionName]; ok {
					opts.PiStatus = &status
				}
				b.WriteString(ui.RenderSessionRow(sessionName, session.LastActivity, layout, opts, m.rowWidth()))
				b.WriteString("\n")
				// line count tracked by renderWithSidebar

				// Show windows if expanded
				if expanded {
					for _, window := range session.Windows {
						b.WriteString(ui.RenderWindowRow(window.Index, window.Name, ui.WindowRowOpts{Selected: false}, m.rowWidth()))
						b.WriteString("\n")
						// line count tracked by renderWithSidebar
					}
				}
			} else {
				// No session - show simple bookmark row
				opts := ui.RowOpts{
					Num:      slot,
					Name:     sessionName,
					Selected: selected,
				}
				b.WriteString(ui.RenderBookmarkRow(sessionName, layout, opts, m.rowWidth()))
				b.WriteString("\n")
				// line count tracked by renderWithSidebar
			}
		}
	}

	// Padding is handled by renderWithSidebar
	hints := ui.UniversalHints
	return m.renderWithSidebar(header.String(), b.String(), ui.BookmarkActions, m.message, hints, m.messageIsError)
}

package config

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"

	"gopkg.in/yaml.v3"
)

// Appearance represents the terminal color scheme mode
type Appearance string

const (
	AppearanceDark  Appearance = "dark"
	AppearanceLight Appearance = "light"
)

// Config holds all configuration options for helm
type Config struct {
	// Terminal appearance mode ("light" or "dark") - controls color adaptation
	Appearance Appearance `yaml:"appearance"`

	// Layout script name to apply when creating new sessions
	Layout string `yaml:"layout"`

	// Directory containing layout scripts
	LayoutDir string `yaml:"layout_dir"`

	// Enable layout scripts feature (when disabled, layouts won't be auto-applied)
	EnableLayouts bool `yaml:"enable_layouts"`

	// Enable Claude Code status integration
	ClaudeStatusEnabled bool `yaml:"claude_status_enabled"`

	// Enable Pi status integration
	PiStatusEnabled bool `yaml:"pi_status_enabled"`

	// Enable git status indicator in session list
	GitStatusEnabled bool `yaml:"git_status_enabled"`

	// Directory for status cache files
	CacheDir string `yaml:"cache_dir"`

	// Base directories for project picker (C-p) - supports multiple paths
	ProjectDirs []string `yaml:"project_dirs"`

	// Scan depth for project directories (default: 2 for owner/repo structure)
	ProjectDepth int `yaml:"project_depth"`

	// Default directory for new sessions created with C-n
	DefaultSessionDir string `yaml:"default_session_dir"`

	// Lazygit popup dimensions
	LazygitPopup PopupConfig `yaml:"lazygit_popup"`

	// Quick-access session bookmarks (slots 1-9, maps to M-1 through M-9)
	Bookmarks []Bookmark `yaml:"bookmarks,omitempty"`

	// Command to run on each dirty repo via 'helm repos dirty --walk'
	// Use {} as placeholder for the repo path, e.g. "lazygit -p {}"
	DirtyWalkthroughCommand string `yaml:"dirty_walkthrough_command,omitempty"`

	// Repositories to ensure are cloned (used by helm setup)
	EnsureCloned []EnsureClonedEntry `yaml:"ensure_cloned,omitempty"`
}

// PopupConfig holds popup dimension settings
type PopupConfig struct {
	Width  string `yaml:"width"`
	Height string `yaml:"height"`
}

// Bookmark represents a quick-access session bookmark
type Bookmark struct {
	Path string `yaml:"path"`
}

// EnsureClonedEntry represents a repository to ensure is cloned.
// Supports both string format (just a URL) and object format (url + post_clone).
type EnsureClonedEntry struct {
	URL       string `yaml:"url"`
	PostClone string `yaml:"post_clone,omitempty"`
}

// UnmarshalYAML allows EnsureClonedEntry to be specified as either a plain string or an object.
func (e *EnsureClonedEntry) UnmarshalYAML(value *yaml.Node) error {
	if value.Kind == yaml.ScalarNode {
		e.URL = value.Value
		return nil
	}
	type plain EnsureClonedEntry
	return value.Decode((*plain)(e))
}

// DefaultConfig returns configuration with sensible defaults
func DefaultConfig() Config {
	home := os.Getenv("HOME")
	return Config{
		Appearance:          AppearanceDark,
		Layout:              "",
		LayoutDir:           filepath.Join(home, ".config", "tmux", "layouts"),
		EnableLayouts:       false,
		ClaudeStatusEnabled: false,
		PiStatusEnabled:     false,
		GitStatusEnabled:    false,
		CacheDir:            filepath.Join(home, ".cache", AppDirName),
		ProjectDirs:         []string{filepath.Join(home, "repos")},
		ProjectDepth:        2,
		DefaultSessionDir:   home,
		LazygitPopup: PopupConfig{
			Width:  "90%",
			Height: "90%",
		},
	}
}

// Path returns the path to the config file
func Path() string {
	home := os.Getenv("HOME")
	return filepath.Join(home, ".config", ConfigDirName(), ConfigFileName)
}

// BookmarksPath returns the path to the separate bookmarks file
func BookmarksPath() string {
	home := os.Getenv("HOME")
	return filepath.Join(home, ".config", ConfigDirName(), BookmarksFileName)
}

// BookmarksFile represents the structure of the bookmarks file
type BookmarksFile struct {
	Bookmarks []Bookmark `yaml:"bookmarks"`
}

// Load reads configuration from file and environment variables.
// Priority: env vars > config file > defaults
func Load() (Config, error) {
	cfg := DefaultConfig()

	// Load from config file if it exists
	configPath := Path()
	if _, err := os.Stat(configPath); err == nil {
		data, err := os.ReadFile(configPath)
		if err != nil {
			return cfg, fmt.Errorf("failed to read config file: %w", err)
		}
		if err := yaml.Unmarshal(data, &cfg); err != nil {
			return cfg, fmt.Errorf("failed to parse config file: %w", err)
		}
	}

	// Expand ~ in paths
	cfg.LayoutDir = expandPath(cfg.LayoutDir)
	cfg.CacheDir = expandPath(cfg.CacheDir)
	cfg.DefaultSessionDir = expandPath(cfg.DefaultSessionDir)

	// Expand ~ in project directories
	for i, d := range cfg.ProjectDirs {
		cfg.ProjectDirs[i] = expandPath(d)
	}

	// Expand ~ in bookmark paths
	for i := range cfg.Bookmarks {
		cfg.Bookmarks[i].Path = expandPath(cfg.Bookmarks[i].Path)
	}

	// Ensure ProjectDepth is at least 1
	if cfg.ProjectDepth < 1 {
		cfg.ProjectDepth = 2
	}

	// Environment variables override config file
	if val := os.Getenv("TMUX_LAYOUT"); val != "" {
		cfg.Layout = val
	}
	if val := os.Getenv("TMUX_LAYOUTS_DIR"); val != "" {
		cfg.LayoutDir = expandPath(val)
	}
	if os.Getenv("TMUX_SESSION_PICKER_CLAUDE_STATUS") == "1" {
		cfg.ClaudeStatusEnabled = true
	}
	if os.Getenv("TMUX_SESSION_PICKER_PI_STATUS") == "1" {
		cfg.PiStatusEnabled = true
	}
	if os.Getenv("TMUX_SESSION_PICKER_GIT_STATUS") == "1" {
		cfg.GitStatusEnabled = true
	}

	// Load bookmarks from separate file (takes priority over config.yml bookmarks)
	if bookmarks, err := LoadBookmarks(); err == nil {
		cfg.Bookmarks = bookmarks
	}
	// If no separate bookmarks file exists, keep bookmarks from config.yml (for migration)

	return cfg, nil
}

// LoadBookmarks reads bookmarks from the separate bookmarks file
func LoadBookmarks() ([]Bookmark, error) {
	bookmarksPath := BookmarksPath()
	if _, err := os.Stat(bookmarksPath); os.IsNotExist(err) {
		return nil, err
	}

	data, err := os.ReadFile(bookmarksPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read bookmarks file: %w", err)
	}

	var bf BookmarksFile
	if err := yaml.Unmarshal(data, &bf); err != nil {
		return nil, fmt.Errorf("failed to parse bookmarks file: %w", err)
	}

	// Expand ~ in bookmark paths
	for i := range bf.Bookmarks {
		bf.Bookmarks[i].Path = expandPath(bf.Bookmarks[i].Path)
	}

	return bf.Bookmarks, nil
}

// Init creates a new config file with commented defaults
func Init() error {
	configPath := Path()
	configDir := filepath.Dir(configPath)

	// Create directory if needed
	if err := os.MkdirAll(configDir, 0755); err != nil {
		return fmt.Errorf("failed to create config directory: %w", err)
	}

	// Check if file already exists
	if _, err := os.Stat(configPath); err == nil {
		return fmt.Errorf("config file already exists at %s", configPath)
	}

	// Write minimal config — schema descriptions provide documentation
	content := `# yaml-language-server: $schema=https://raw.githubusercontent.com/black-atom-industries/helm/main/schema.json
appearance: dark
project_dirs:
  - ~/repos
`

	if err := os.WriteFile(configPath, []byte(content), 0644); err != nil {
		return fmt.Errorf("failed to write config file: %w", err)
	}

	return nil
}

// SaveBookmarks writes bookmarks to the separate bookmarks file
// This preserves comments in the main config.yml
func (cfg *Config) SaveBookmarks() error {
	bf := BookmarksFile{Bookmarks: cfg.Bookmarks}
	data, err := yaml.Marshal(bf)
	if err != nil {
		return fmt.Errorf("failed to marshal bookmarks: %w", err)
	}

	// Ensure config directory exists
	bookmarksPath := BookmarksPath()
	if err := os.MkdirAll(filepath.Dir(bookmarksPath), 0755); err != nil {
		return fmt.Errorf("failed to create config directory: %w", err)
	}

	if err := os.WriteFile(bookmarksPath, data, 0644); err != nil {
		return fmt.Errorf("failed to write bookmarks file: %w", err)
	}
	return nil
}

// expandPath expands ~ to the user's home directory
func expandPath(path string) string {
	if len(path) > 0 && path[0] == '~' {
		home := os.Getenv("HOME")
		return filepath.Join(home, path[1:])
	}
	return path
}

// RepoInfo represents a cloned repository with its location
type RepoInfo struct {
	Name string // "owner/repo"
	Path string // absolute path on disk
}

// ListClonedRepos returns already-cloned repos in owner/repo format.
// Scans the base path at depth 2 (owner/repo structure).
func ListClonedRepos(basePath string) ([]string, error) {
	var repos []string

	owners, err := os.ReadDir(basePath)
	if err != nil {
		if os.IsNotExist(err) {
			return []string{}, nil
		}
		return nil, err
	}

	for _, owner := range owners {
		if !owner.IsDir() {
			continue
		}

		ownerPath := filepath.Join(basePath, owner.Name())
		repoEntries, err := os.ReadDir(ownerPath)
		if err != nil {
			continue
		}

		for _, repo := range repoEntries {
			if !repo.IsDir() {
				continue
			}

			gitPath := filepath.Join(ownerPath, repo.Name(), ".git")
			if _, err := os.Stat(gitPath); err == nil {
				repos = append(repos, owner.Name()+"/"+repo.Name())
			}
		}
	}

	sort.Strings(repos)
	return repos, nil
}

// FilterUncloned returns repos from available that are not in cloned
func FilterUncloned(available, cloned []string) []string {
	clonedSet := make(map[string]bool)
	for _, r := range cloned {
		clonedSet[r] = true
	}

	var uncloned []string
	for _, r := range available {
		if !clonedSet[r] {
			uncloned = append(uncloned, r)
		}
	}

	return uncloned
}

// ListAllRepos scans all project directories and returns every cloned repo with its path.
// Deduplicates by name — first occurrence wins.
func ListAllRepos(projectDirs []string) ([]RepoInfo, error) {
	seen := make(map[string]bool)
	var all []RepoInfo

	for _, dir := range projectDirs {
		names, err := ListClonedRepos(dir)
		if err != nil {
			continue
		}
		for _, name := range names {
			if seen[name] {
				continue
			}
			seen[name] = true
			all = append(all, RepoInfo{
				Name: name,
				Path: filepath.Join(dir, name),
			})
		}
	}

	return all, nil
}

